import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import ArticleBigImageCard from '../components/ArticleBigImageCard'
import ArticleMediumImageCard from '../components/ArticleMediumImageCard'
import ArticleTinyImageCard from '../components/ArticleTinyImageCard'
import ArticleMagWrapper from '../components/ArticleMagWrapper'

const ImageSection = styled.div `
width:86%;
margin:30px auto;
display:flex;
align-items:center;
justify-content:space-between;
&+& {
	margin-top:60px;
}
`


const BigImageWrapper = styled.div `
width:600px;
height:500px;
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_1280,q_90,f_auto,dpr_auto/v1668434286/maiqdcmzqyxvoc8rpfvx.jpg');
background-size:cover;
background-position:center;
`

const MediumImageWrapper = styled.div `
width:380px;
height:550px;
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_768,q_90,f_auto,dpr_auto/v1668091944/rkizkvtm9kvr75436bns.jpg');
background-size:cover;
background-position:center;
`

const TinyImageWrapper = styled.div `
border-top:1px solid black;
border-bottom:1px solid black;
padding:10px 0;
font-size:0.9rem;
height:90px;
width:280px;
display:flex;
`

const BigFooter = styled.div `
width:600px;
height:140px;
background-color:white;
font-size:1rem;
padding-top:10px;
box-sizing:border-box;
`

const MediumFooter = styled.div `
width:300px;
height:140px;
background-color:white;
font-size:1rem;
padding-top:10px;
box-sizing:border-box;
`

const Title = styled.div `
font-weight:900;
`

const TinyTitle = styled(Title) `
font-size:0.6rem;
`

const Content = styled.div `
white-space:break-spaces;
margin-top:15px;
overflow: hidden;
text-overflow: ellipsis;
display: -webkit-box;
-webkit-line-clamp: 2;
-webkit-box-orient: vertical;
`

const TinyImage = styled.div `
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_480,q_90,f_auto,dpr_auto/v1662729938/ergnjjf7wh3uzlqyz8nm.jpg');
background-size:cover;
background-position:center;
width:60px;
height:90px;
margin-right:20px;
`

const TinyImageInfo = styled.div `
display:flex;
flex-direction:column;
justify-content:space-between;
align-items:center;
width:200px;
`

const LeftImagePart = styled.div `
height:600px;
display:flex;
flex-direction:column;
justify-content:space-between;
`

const RightImagePart = styled.div `
width:280px;
`

const SmallImage = styled.div `
width:420px;
height:280px;
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_768,q_90,f_auto,dpr_auto/v1667397617/afzrg9qecta1wgm1zff0.jpg');
background-position:center;
background-size:center;
`

const SmallImageInfo = styled.div `
width:350px;
height:300px;
display:flex;
flex-direction:column;
margin-left:30px;
`

const SmallTitle = styled.div `
font-size:0.9rem;
font-weight:900;
`
const SmallContent = styled.div `
font-size:0.9rem;
`

const Div = styled.div `
display:flex;
`

const TinyImageWrapperBigger = styled( TinyImageWrapper) `
height:90px;
&+& {
	border-top:0px;
	border-bottom:1px solid black;
}
`

export default function Articles () {
	return (
		<>
		<Header/>
		<Navbar/>
		<ImageSection>
			<ArticleBigImageCard/>
			<ArticleBigImageCard/>
		</ImageSection>
		<ImageSection>
			<ArticleMediumImageCard/>
			<ArticleMediumImageCard/>
			<ArticleMediumImageCard/>
		</ImageSection>
		<ImageSection>
			<ArticleBigImageCard/>
			<ArticleBigImageCard/>
		</ImageSection>
		<ImageSection>
			<ArticleTinyImageCard/>
			<ArticleTinyImageCard/>
			<ArticleTinyImageCard/>
			<ArticleTinyImageCard/>
		</ImageSection>
		<ImageSection>
			<ArticleMagWrapper/>
		</ImageSection>
		<ImageSection>
		<ArticleMediumImageCard/>
			<ArticleMediumImageCard/>
			<ArticleMediumImageCard/>
		</ImageSection>

		</>

	)
}
